external_knowledge:
; Average rating refers to the mean of all ratings received by a business from its reviews; 
; Review count refers to the total number of reviews a business has received;
; "Top-rated" in this context means having the highest average rating within a category; 
; Financial advisor refers to the contact person in a business holding the title of 'Financial Advisor'.

sql:
SELECT business_id, AVG(rating) AS average_rating
FROM business_reviews
GROUP BY business_id;

SELECT review_text
FROM business_reviews
WHERE review_status = 'approved';

external_knowledge:
- 'earned a perfect reputation' refers to a rating of 5 stars; 
- 'stood the test of time' means the company has been established for more than 10 years; 
- 'given the green light' means the review status is 'approved'.

sql:
SELECT review_text
   FROM business_reviews
   WHERE review_date = (SELECT MAX(review_date) FROM business_reviews);
